import{_ as t,o,c as n,a3 as a}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Meetings","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Meetings | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/meetings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Meetings | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/meetings"}]]},"headers":[],"relativePath":"user-guide/meetings.md","filePath":"user-guide/meetings.md","lastUpdated":1784743690000}'),i={name:"user-guide/meetings.md"};function r(s,e,l,c,d,g){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="meetings" tabindex="-1">Meetings <a class="header-anchor" href="#meetings" aria-label="Permalink to &quot;Meetings&quot;">​</a></h1><p>Use <strong>Meetings</strong> to schedule workspace meetings, invite teammates (and external guests by email), connect a workspace Zoom or Google Meet account, and set one reminder before start.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><ul><li>Workspace must have the <strong>Meetings</strong> module installed (included by default; requires <strong>Calendar</strong>).</li><li>Your role needs <code>meetings.view</code> (and <code>create</code> / <code>update</code> / <code>delete</code> for edits).</li><li>Connecting Zoom/Google requires <code>meetings.manage_integrations</code>.</li></ul><h2 id="visibility" tabindex="-1">Visibility <a class="header-anchor" href="#visibility" aria-label="Permalink to &quot;Visibility&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>What you see</th></tr></thead><tbody><tr><td>Staff (no <code>view_all</code>)</td><td>Meetings you created, host, or are invited to</td></tr><tr><td>Owner / Admin / Manager (<code>meetings.view_all</code>)</td><td>All workspace meetings</td></tr></tbody></table><p>Invitees use the Meetings list/detail as their source of truth. Calendar shows the <strong>host’s</strong> projected event (Calendar ACLs remain organizer-scoped).</p><h2 id="schedule-a-meeting" tabindex="-1">Schedule a meeting <a class="header-anchor" href="#schedule-a-meeting" aria-label="Permalink to &quot;Schedule a meeting&quot;">​</a></h2><ol><li>Open <strong>Meetings</strong> from the workspace nav.</li><li>Click <strong>New meeting</strong>.</li><li>Enter title, start/end, timezone, optional agenda.</li><li>Choose a provider: <ul><li><strong>None</strong> — optional manual join URL</li><li><strong>Google Meet</strong> / <strong>Zoom</strong> — requires a connected workspace account</li></ul></li><li>Add internal invitees and optional external guests (<code>Name &lt;email@domain&gt;</code> per line).</li><li>Optionally set <strong>one reminder</strong> (15 minutes, 1 hour, 24 hours, or custom minutes before start).</li><li>Save.</li></ol><p>Host defaults to you. Users with <code>meetings.assign_host</code> can reassign the host.</p><h2 id="connect-zoom-or-google-meet" tabindex="-1">Connect Zoom or Google Meet <a class="header-anchor" href="#connect-zoom-or-google-meet" aria-label="Permalink to &quot;Connect Zoom or Google Meet&quot;">​</a></h2><ol><li>Open Meetings → <strong>Integrations</strong> (owners/admins with <code>meetings.manage_integrations</code>).</li><li>Click the <strong>info</strong> icon next to Zoom or Google Meet for step-by-step setup (create the provider OAuth app, required scopes, and how to connect in SaleOS).</li><li>Create an OAuth app in Google Cloud / Zoom Marketplace for <strong>your organization</strong>.</li><li>Paste the shown <strong>OAuth callback URL</strong> into that app’s redirect settings (copy from Integrations or the setup guide).</li><li>For Zoom, add scopes <code>meeting:write:meeting</code>, <code>meeting:read:meeting</code>, <code>meeting:delete:meeting</code>, and <code>user:read:user</code> (missing write → create error 4711; missing delete → remote cancel fails while SaleOS still cancels locally).</li><li>For Google, enable the Meet API and register a <strong>localhost</strong> or <strong>HTTPS</strong> redirect URI (Google rejects <code>http://*.test</code>). Meet creates a joinable space link (not a full Calendar conference).</li><li>Save your workspace <strong>Client ID</strong> and <strong>Client secret</strong> (optional webhook secret is reserved for a future native webhook integration).</li><li>Click <strong>Connect account</strong> and approve access with the workspace Google/Zoom user.</li></ol><p>Staff then schedule using those workspace connections — not personal accounts or platform-wide keys.</p><p>If a selected provider is not connected, scheduling with that provider is blocked. If you change Zoom/Google scopes later, disconnect and connect again so a new token is issued.</p><h2 id="reminder" tabindex="-1">Reminder <a class="header-anchor" href="#reminder" aria-label="Permalink to &quot;Reminder&quot;">​</a></h2><p>Creators can set <strong>one</strong> reminder offset. At that time, the creator, host, and invitees receive:</p><ul><li>In-app notification</li><li>Web push (when subscribed)</li><li>Email</li></ul><p>External email-only guests receive email only. Cancelling or rescheduling the meeting updates or cancels the pending reminder.</p><h2 id="cancel-vs-delete" tabindex="-1">Cancel vs delete <a class="header-anchor" href="#cancel-vs-delete" aria-label="Permalink to &quot;Cancel vs delete&quot;">​</a></h2><ul><li><strong>Cancel</strong> — keeps the record, marks status <code>cancelled</code>, cancels the Calendar projection and pending reminder. Remote Zoom/Google delete is best-effort: if the provider rejects delete (often missing <code>meeting:delete:meeting</code>), the meeting stays cancelled in SaleOS and <code>provider_sync_error</code> explains the remote failure.</li><li><strong>Delete</strong> — soft-deletes the meeting and removes the Calendar projection (same best-effort remote delete).</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Workspace <strong>Settings → General</strong> includes <strong>Default meeting provider</strong> (<code>meetings_default_provider</code>: <code>none</code> | <code>google_meet</code> | <code>zoom</code>) used to preselect the schedule form.</p>',22)])])}const p=t(i,[["render",r]]);export{h as __pageData,p as default};
